SELECT *
FROM paper_info
WHERE student_id = #{studentId}
AND is_deleted = 0
ORDER BY create_time DESC
LIMIT 1;

WITH total_count AS ( SELECT COUNT(*) as total FROM paper_info WHERE teacher_id = #{teacherId} AND is_deleted = 0 AND similarity_rate IS NOT NULL AND similarity_rate > 0
AND submit_time >= #{startDate}
AND submit_time <= #{endDate}
) SELECT CASE WHEN similarity_rate < 10 THEN '0-10%' WHEN similarity_rate < 20 THEN '10-20%' WHEN similarity_rate < 30 THEN '20-30%' WHEN similarity_rate < 40 THEN '30-40%' WHEN similarity_rate < 50 THEN '40-50%' ELSE '50%以上' END as `range`, COUNT(*) as paperCount, ROUND(COUNT(*) * 100.0 / (SELECT total FROM total_count), 1) as percentage FROM paper_info WHERE teacher_id = #{teacherId} AND is_deleted = 0 AND similarity_rate IS NOT NULL AND similarity_rate > 0
AND submit_time >= #{startDate}
AND submit_time <= #{endDate}
GROUP BY CASE WHEN similarity_rate < 10 THEN '0-10%' WHEN similarity_rate < 20 THEN '10-20%' WHEN similarity_rate < 30 THEN '20-30%' WHEN similarity_rate < 40 THEN '30-40%' WHEN similarity_rate < 50 THEN '40-50%' ELSE '50%以上' END ORDER BY MIN(similarity_rate)

SELECT su.college_name as collegeName, COUNT(DISTINCT pi.student_id) as studentCount, COUNT(*) as reviewCount, ROUND(AVG(pi.similarity_rate), 1) as avgSimilarity FROM paper_info pi LEFT JOIN sys_user su ON pi.student_id = su.id WHERE pi.teacher_id = #{teacherId} AND pi.is_deleted = 0 AND su.college_name IS NOT NULL AND su.college_name != ''
AND pi.submit_time >= #{startDate}
AND pi.submit_time <= #{endDate}
GROUP BY su.college_name ORDER BY studentCount DESC, reviewCount DESC

SELECT COUNT(*)
FROM paper_info
WHERE teacher_id = #{teacherId}
AND is_deleted = 0
AND similarity_rate IS NOT NULL
AND similarity_rate > 0

    AND submit_time >= #{startDate}


    AND submit_time <= #{endDate}
